/**
 * method
 * @name f_save
 * @description 중기실적 저장
 */
scwin.f_save = async function () {
  if (!ds_heavyEquipWorkResults.getRowCount()) {
    return;
  }
  let isSupplyOil = false; /* 주유실적 등록 유무   */
  let isSupplyOilOnly = false; /*주유실적만 등록한 경우 */

  let workResultsRow = gr_heavyEquipWorkResults.getFocusedRowIndex();
  let basisInfo = ds_heavyEquipBasisInformation.getRowJSON(0);
  if (!ds_heavyEquipWorkResults.getModifiedIndex().length && (!ds_oilingResults.getModifiedIndex().length || ds_oilingResults.getCellData(0, "oilStatCd") == "" && ds_oilingResults.getRowStatus(0) == "C") && !ds_heavyEquipBasisInformation.getModifiedIndex().length && !ds_heavyEquipNonOperationHour.getModifiedIndex().length) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["중기실적"]); // "@은(는) 변경된 사항이 없습니다."
    return;
  }
  if (ds_oilingResults.getRowStatus(0) == "C" && (ds_oilingResults.getCellData(0, "oilStatCd") != "" || ds_oilingResults.getCellData(0, "oilingVol") > 0)) {
    isSupplyOil = true;
  }

  // 검색조건 필수 입력 체크
  let workResults = ds_heavyEquipWorkResults.getAllJSON();
  let modifiedIdx = ds_heavyEquipWorkResults.getModifiedIndex(); //CUD 작업이 일어난 경우
  let iRowObj = null;
  let jRowObj = null;
  for (let i of modifiedIdx) {
    iRowObj = workResults[i];
    if (iRowObj.rowStatus == "C") {
      /* 1 : Insert*/
      for (let j = 0; j < workResults.length; j++) {
        jRowObj = workResults[j];
        if (i != j && iRowObj.wrkIndictNo == jRowObj.wrkIndictNo && iRowObj.eqCd == jRowObj.eqCd && iRowObj.impExpClsCd == jRowObj.impExpClsCd) {
          await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터는 중복 데이터이므로 입력하실 수 없습니다.");
          gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
          return;
        }
      }
    }
    if (iRowObj.wrkIndictNo.trim() == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 작업지시번호는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      ed_wrkIndictNo.focus();
      return;
    }

    // 본선이면
    if (iRowObj.wrkIndictClsCd == "P") {
      if (iRowObj.impExpClsCd == "Y") {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 수출입구분은 필수입력항목 입니다.");
        gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
        ;
        lc_impExpClsCd.focus();
        return;
      }
    }
    if (iRowObj.wrkStpCd.trim() == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 작업단계는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      lc_wrkStpCd.focus();
      return;
    }
    if (iRowObj.rowStatus == "D") {
      continue;
    }
    //삭제가 아닌 경우 ==> 2:삭제
    if (iRowObj.wrkStDt.trim() == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 작업시작일자는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      ica_wrkStDt.focus();
      return;
    }
    if (iRowObj.wrkStHh.trim() == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 작업시작시간는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      ed_wrkStHh.focus();
      return;
    }
    if (iRowObj.wrkEndDt.trim() == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 작업종료일자는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      ica_wrkEndDt.focus();
      return;
    }
    if (iRowObj.wrkEndHh.trim() == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 작업종료시간는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      ed_wrkEndHh.focus();
      return;
    }
    if (!(await scwin.f_validateWrkTime(iRowObj))) {
      return false;
    }

    //작업시간이 겹치지 않도록 체크함
    for (let j = 0; j < workResults.length; j++) {
      jRowObj = workResults[j];
      if (jRowObj.rowStatus == "D" || j == i) {
        continue;
      }
      if (!(jRowObj.wrkStDt.trim() > iRowObj.wrkEndDt.trim() || jRowObj.wrkStDt.trim() == iRowObj.wrkEndDt.trim() && jRowObj.wrkStHh.trim() >= iRowObj.wrkEndHh.trim() || jRowObj.wrkEndDt.trim() < iRowObj.wrkStDt.trim() || jRowObj.wrkEndDt.trim() == iRowObj.wrkStDt.trim() && jRowObj.wrkEndHh.trim() <= iRowObj.wrkStHh.trim())) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적의 작업시간이 " + (j + 1) + "번째 작업실적의 작업시간과 중복됩니다.");
        gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
        ;
        ica_wrkStDt.focus();
        return;
      }
    }
    if (isSupplyOil && ds_oilingResults.getCellData(0, "oilStatCd") == "") {
      await $c.gus.cfAlertMsg($p, "주유 실적 등록시  주유소는  필수입력항목 입니다.");
      return;
    } else if (isSupplyOil && ds_oilingResults.getCellData(0, "oilingVol") == 0) {
      await $c.gus.cfAlertMsg($p, "주유 실적 등록시  주유량은 0보다 커야 합니다.");
      return;
    }
    isSupplyOilOnly = false;
    //주유 실적만 등록하는 경우인지 Check 하는 부분.
    if (isSupplyOil &&
    // 주유 실적이 있고,
    iRowObj.pchsPcost == 0 &&
    //매입원가
    iRowObj.ctrlPchsPcost == 0 &&
    //조정원가
    iRowObj.tformEqPchsPcost == 0) {
      //변형장비 원가
      isSupplyOilOnly = true; // 주유 실적만 등록하는 경우임.
    }

    // 자사가 아니면
    if (basisInfo.posnClsCd != 'J') {
      // 용차인 경우 실적 없이 주유 등록만 한 경우  매입거래처 등의 정보 없어도 되지만, 중기 실적 있으면 매입거래처등의 정보 Check 해야 함.
      if (!isSupplyOilOnly && iRowObj.pchsClntNo == "") {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 매입거래처는 필수입력항목 입니다.");
        gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
        ;
        ed_pchsClntNo.focus();
        return;
      }

      // 용차인 경우 실적 없이 주유 등록만 한 경우  협력업체는  정보 없어도 되지만, 중기 실적 있으면 협력 업체는 정보 Check 해야 함.
      if (!isSupplyOilOnly && iRowObj.copCoClntNo == "") {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 협력업체는 필수입력항목 입니다.");
        gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
        ;
        ed_copCoClntNo.focus();
        return;
      }
    }
    if (iRowObj.pchsDeptCd == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 매입부서는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      ed_pchsDeptCd.focus();
      return;
    }

    //  실적 없이 주유 등록만 한 경우  매입원가는  정보 없어도 되지만, 중기 실적 있으면 매입원가는  정보 Check 해야 함.
    if (!isSupplyOilOnly && iRowObj.pchsPcost == 0) {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 매입원가는 필수입력항목 입니다.");
      gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
      ;
      but_CalcPchsPcost.focus();
      return;
    }
    //  실적 없이 주유 등록만 한 경우 조정원가 Check 안하지만, 중기실적이 있는 경우는  조정금액이 있으면 조정사유 있어야 함.
    if (!isSupplyOilOnly && iRowObj.ctrlPchsPcost != 0 && iRowObj.ctrlPchsPcostRsn == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 작업실적  데이터의 조정사유는 필수입력항목 입니다.");
      lc_ctrlPchsPcostRsn.focus();
      return;
    }
  }
  for (let i = 0; i < ds_heavyEquipNonOperationHour.getRowCount(); i++) {
    let rowObj = ds_heavyEquipNonOperationHour.getRowJSON(i);
    if (rowObj.nonoprtHhCnt == 0 && rowObj.nonoprtMintCnt == 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["비가동시간"]);
      return;
    }
    if (rowObj.nonoprtRsnCd == "") {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["비가동사유"]);
      return;
    }
  }
  if (!(await $c.win.confirm($p, "저장하시겠습니까?"))) {
    return;
  }
  scwin.pos_groupCode = workResultsRow; // 저장 전의 위치 저장
  scwin.heavyEquipWorkIndicationRow = gr_heavyEquipWorkIndication.getFocusedRowIndex();
  ds_heavyEquipBasisInformation.modifyRowStatus(0, "C");
  ds_heavyEquipWorkIndication.modifyRowStatus(scwin.heavyEquipWorkIndicationRow, "C");
  $c.sbm.execute($p, sbm_save);
};

