/**
 * method
 * @name f_validateWrkTime
 * @description 작업시간 입력시 유효성체크
 */
scwin.f_validateWrkTime = async function (rowObj) {
  const nextDay = $c.date.addDate($p, ed_wrkDt.getValue(), 1);
  if (rowObj.shiftClsCd == 'D') {
    if (rowObj.wrkStDt.trim().length > 0 && rowObj.wrkStDt != ed_wrkDt.getValue()) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_030 + "작업일자와 같은날만 가능합니다", ["주간의 작업시작일자"]);
      ica_wrkStDt.focus();
      return false;
    }
  } else {
    if (rowObj.wrkStDt.trim().length > 0 && (rowObj.wrkStDt < ed_wrkDt.getValue() || rowObj.wrkStDt > nextDay)) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_030 + "작업일자 하루이후까지만 가능합니다", ["야간/심야의 작업시작일자"]);
      ica_wrkStDt.focus();
      return false;
    }
    if (rowObj.wrkEndDt == nextDay) {
      if (rowObj.wrkEndHh.trim() > '0800') {
        await $c.gus.cfAlertMsg($p, "야간/심야의 작업종료시간은 08시 이전이어야 합니다.");
        ed_wrkEndHh.focus(); // 시작시간에 focus
        return;
      }
    }
  }
  if (rowObj.wrkStDt.trim().length == 0 || rowObj.wrkEndDt.trim().length == 0) {
    return true;
  }
  if (rowObj.wrkStDt.trim().length != 8 || rowObj.wrkEndDt.trim().length != 8 || !$c.gus.cfIsAfterDate($p, rowObj.wrkStDt, rowObj.wrkEndDt, false)) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ica_wrkStDt.focus();
    return false;
  }
  if (rowObj.wrkStHh.trim().length == 0) return true;
  if (rowObj.wrkStHh.trim().length != 4) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
    ed_wrkStHh.focus();
    return false;
  }
  if (rowObj.wrkEndDt.trim().length > 0 && (rowObj.wrkEndDt < ed_wrkDt.getValue() || rowObj.wrkEndDt > nextDay)) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_030 + "작업일자 하루이후까지만 가능합니다", ["종료일자"]);
    ica_wrkEndDt.focus();
    return false;
  }
  if (rowObj.wrkStDt.trim().length == 0 || rowObj.wrkEndDt.trim().length == 0) {
    return true;
  }
  if (rowObj.wrkStDt.trim().length != 8 || rowObj.wrkEndDt.trim().length != 8 || !$c.gus.cfIsAfterDate($p, rowObj.wrkStDt, rowObj.wrkEndDt, false)) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ica_wrkEndDt.focus();
    return false;
  }
  if (rowObj.wrkEndHh.trim().length == 0) {
    return true;
  }
  if (rowObj.wrkEndHh.trim().length != 4) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
    ed_wrkEndHh.focus();
    return false;
  }
  if (rowObj.wrkStHh.substring(0, 2) > "23") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
    ed_wrkStHh.focus();
    return;
  }
  if (rowObj.wrkStHh.substring(2, 4) > "59") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkStHh.focus();
    return;
  }
  if (rowObj.wrkEndHh.substring(0, 2) > "24") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  if (rowObj.wrkEndHh.substring(0, 2) == "00" && rowObj.wrkEndHh.substring(2, 4) == "00") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  if (rowObj.wrkEndHh.substring(0, 2) == "24" && rowObj.wrkEndHh.substring(2, 4) > "00") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  if (rowObj.wrkEndHh.substring(2, 4) > "59") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  if (rowObj.wrkStDt.trim() == rowObj.wrkEndDt.trim() && rowObj.wrkStHh.trim() >= rowObj.wrkEndHh.trim()) {
    await $c.gus.cfAlertMsg($p, "시작시간을 종료시간보다 작게 입력하여 주십시오.");
    ed_wrkStHh.focus();
    return false;
  }
  return true;
};

/**
 * method
 * @name f_CalcWrkTime
 * @description 작업시간계산
 */
scwin.f_CalcWrkTime = async function () {
  const wrkStDt = ica_wrkStDt.getValue().trim();
  const wrkStHh = ed_wrkStHh.getValue().trim();
  const wrkEndDt = ica_wrkEndDt.getValue().trim();
  const wrkEndHh = ed_wrkEndHh.getValue().trim();
  if (wrkStDt.length != 8 || wrkStHh.length != 4 || wrkEndDt.length != 8 || wrkEndHh.length != 4) {
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, wrkStDt, wrkEndDt, false) || wrkStDt == wrkEndDt && wrkStHh > wrkEndHh) {
    return;
  }
  let v_diff = 0; //총시간차이
  const v_StHh = $c.num.parseInt($p, wrkStHh.substring(0, 2)); //시작시간
  const v_StMm = $c.num.parseInt($p, wrkStHh.substring(2, 4)); //시작분
  const v_EndHh = $c.num.parseInt($p, wrkEndHh.substring(0, 2)); //종료시간
  const v_EndMm = $c.num.parseInt($p, wrkEndHh.substring(2, 4)); //종료분

  let v_daysBetween = await scwin.cfDaysBetween(wrkStDt, wrkEndDt);
  if (v_daysBetween > 0) {
    // 날짜차이*24시간*60분 + (24시간*60분 - 시작시간*60분 + 시작분수) + (종료시간*60분 + 종료분수)
    v_diff = (v_daysBetween - 1) * 24 * 60 + (24 * 60 - v_StHh * 60 + v_StMm) + (v_EndHh * 60 + v_EndMm);
  } else {
    // 종료시간 - 시작시간
    v_diff = v_EndHh * 60 + v_EndMm - (v_StHh * 60 + v_StMm);
  }
  const v_diffHh = $c.num.parseInt($p, v_diff / 60); //시간차이
  const v_diffMm = $c.num.parseInt($p, v_diff % 60); //분차이

  let row = gr_heavyEquipWorkResults.getFocusedRowIndex();
  ds_heavyEquipWorkResults.setCellData(row, "totInputHhCnt", v_diffHh);
  ds_heavyEquipWorkResults.setCellData(row, "totInputMintCnt", v_diffMm);
  scwin.f_CalcNonOperationHour(); //실가동시간도 같이 계산
};

/**
* method
* @name cfDaysBetween
* @description
*/
scwin.cfDaysBetween = async function (stDt, endDt) {
  let v_daysBetween = 0;
  if (!$c.date.isDate($p, stDt)) {
    await $c.win.alert($p, "시작일자는 'YYYYMMDD' 형식이어야 합니다.");
  } else if (!$c.date.isDate($p, endDt)) {
    await $c.win.alert($p, "종료일자는 'YYYYMMDD' 형식이어야 합니다.");
  } else {
    v_daysBetween = $c.date.diffDate($p, stDt, endDt);
  }
  return v_daysBetween;
};

