/**
 * method
 * @name f_cfRefreshMandSign
 * @description 필수입력 표시 변경
 */
scwin.f_cfRefreshMandSign = function () {
  let compArr = [{
    comp: lc_impExpClsCd,
    target: tbx_impExpClsCd,
    isCombo: true
  }, {
    comp: ed_pchsPcost,
    target: tbx_pchsPcost
  }, {
    comp: lc_pchsAdjmStdCd,
    target: tbx_pchsAdjmStdCd,
    isCombo: true
  }, {
    comp: ed_copCoClntNo,
    target: tbx_copCoClntNo
  }, {
    comp: ed_pchsClntNo,
    target: tbx_pchsClntNo
  }, {
    comp: ed_pchsAdptHhCnt,
    target: tbx_pchsAdptHhCnt
  }, {
    comp: ed_wrkWt,
    target: tbx_wrkWt
  }, {
    comp: lc_ctrlPchsPcostRsn,
    target: tbx_ctrlPchsPcostRsn,
    isCombo: true
  }];
  for (let item of compArr) {
    if (item.comp.options.mandatory === "true") {
      if (!item.target.hasClass("req")) {
        item.target.addClass("req");
      }
    } else {
      if (item.target.hasClass("req")) {
        item.target.removeClass("req");
      }
    }
  }
};

/**
 * event
 * @name sbm_searchHeavyEquipWorkResults_submitdone
 * @description
 */
scwin.sbm_searchHeavyEquipWorkResults_submitdone = async function (e) {
  if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
    return;
  }

  //for=ds_heavyEquipWorkIndication
  let rowCnt = ds_heavyEquipWorkIndication.getRowCount();
  tbx_totalRows1.setValue(rowCnt);
  if (rowCnt) {
    gr_heavyEquipWorkIndication.setFocusedCell(scwin.heavyEquipWorkIndicationRow, gr_heavyEquipWorkIndication.getFocusedColumnIndex() ?? 0, false);
  }

  //for=ds_heavyEquipBasisInformation
  if (ds_heavyEquipBasisInformation.getRowCount()) {
    ds_heavyEquipBasisInformation.setRowPosition(0, false);
    await scwin.f_switchObjMode(5);
    await scwin.f_switchObjMode(4);
  }

  //for=ds_heavyEquipWorkResults
  rowCnt = ds_heavyEquipWorkResults.getRowCount();
  if (rowCnt) {
    gr_heavyEquipWorkResults.setFocusedCell(scwin.pos_groupCode, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false); // 저장전 위치로 이동
  }
  tbx_totalRows2.setValue(rowCnt);
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    await scwin.f_switchObjMode(1);
    await scwin.f_switchObjMode(5);
  } else {
    await scwin.f_switchObjMode(4);
  }

  //for=ds_oilingResults
  if (!ds_oilingResults.getRowCount()) {
    ds_oilingResults.insertJSON(0, [{
      oilingVol: "0"
    }]);
    ds_oilingResults.setCellData(0, "eqCd", hd_eqCd.getValue());
    ds_oilingResults.setCellData(0, "wrkDt", ed_wrkDt.getValue());
  }
  ds_oilingResults.setRowPosition(0, false);
};

/**
 * event
 * @name sbm_searchPchsPcost_submitdone
 * @description
 */
scwin.sbm_searchPchsPcost_submitdone = async function (e) {
  if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
    return;
  }
  let rowCnt = ds_pchsPcost.getRowCount();
  //원가계산 관련 메세지 처리
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, "해당 요율을 조회하는데 실패하였습니다.");
    ed_pchsPcost.setValue("0");
    ed_upr.setValue("0");
  } else {
    let rowObj = ds_pchsPcost.getRowJSON(0);
    if (rowObj.uprKnd == 0) {
      // 해당 요율이 없습니다. -> 멈춤
      await $c.gus.cfAlertMsg($p, "해당 요율이 없습니다.");
      ed_pchsPcost.setValue("0");
      ed_upr.setValue("0");
      return;
    }
    if (rowObj.uprKnd == 3 && rowObj.ctrtEndYn == 1) {
      // 계약요율의 계약기간이 만료됨 -> 계속 진행
      await $c.gus.cfAlertMsg($p, "계약기간이 만료된 계약요율입니다.");
    }
    ed_pchsPcost.setValue(rowObj.pchsPcost);
    ed_upr.setValue(rowObj.upr?.toString() ?? "");
  }
};

